-- Course: Carradale Golf Club
-- Location: Carradale, Scotland
-- Type: 9-hole course played twice for WHS 18-hole (asymmetric for men's White)
-- Generated by course-ingest
-- Sources:
--   CR/Slope (Red ladies): GolfSherpa golfsherpa.co.uk/courses/scotland/carradale-golf-course
--     CR 62.8 confirmed against GolfShake SSS 63 (consistent rounding).
--     Slope 105: GolfSherpa only — no contradiction found (WARN: single-source).
--   Distances (Red H1-H9): GolfPass golfpass.com/travel-advisor/courses/17051-carradale-golf-club
--     H1-H9 = 143,310,219,242,254,244,167,120,261 = 1960 yards per nine; ×2 = 3920 yards total.
--     Back nine (H10-H18) same physical holes, identical distances.
--   Pars per hole (Women): Club website carradalegolf.com/course — confirmed M/W PAR per hole.
--     H3: M=par3, W=par4 (219 yards ladies; consistent with R&A guideline for women's par4).
--     All other holes: W=M par. Red 9h par = 33, 18h par = 66 = 33+33 (symmetric, no asymmetry).
--   SI H1-H9 (ladies): GolfPass Handicap (W) column — 15,1,9,3,17,7,11,13,5 (all odd, WHS convention).
--   SI H10-H18 (ladies): derived by +1 convention (standard Scottish 9-hole twice-around):
--     back-nine SI = front-nine SI + 1 per hole. All-odd front → all-even back; covers 1-18 uniquely.
--     Convention matches Anstruther and Aigas staging precedent. Values are DERIVED, not sourced.
--   Per-nine CR/slope: front9 = back9 = 62.8/2 = 31.4 each; slope same both nines.
--     Per-nine CRs derived (not independently sourced) — consistent with symmetric 33+33 layout.
-- Name note: scotland_golf_courses.csv lists this course as "Carradale Golf Course"; official club
--   website (carradalegolf.com) and GolfPass use "Carradale Golf Club". SQL uses club's own name.
-- Tees emitted: Red (ladies)
-- Tees NOT emitted (reasons documented below):
--   White (mens) 4576yds par65 — DROPPED:
--     (1) CR contradictory: GolfSherpa CR 62.9 vs GolfShake SSS 64 (likely stale); no authoritative
--         single confirmed value.
--     (2) 18h par 65 ≠ 9h par 32 × 2 = 64: one hole changes par on the back nine (par3→par4),
--         but the club website shows only M PAR for holes played once — which hole plays differently
--         on the second rotation (H10-H18) cannot be determined from any available source.
--     (3) Front-9 SI {14,6,2,10,12,3,16,5,8} is NOT all-odd: the +1 convention cannot be applied
--         without collision. Back-nine SI unverifiable and must not be fabricated.
--   Yellow (mens) 3988yds par64 — DROPPED:
--     No per-hole distances on GolfPass. CR 60.8/slope 100 GolfSherpa single-source.
--     18h par contradictory: GolfPass 64 vs original validator claim 66.
--   Blue 3920yds par66 — DROPPED:
--     No CR/slope from any source. No per-hole distances. Gender unspecified.
-- WARN: Red slope 105 is single-source (GolfSherpa); no confirming or contradicting value found.
-- WARN: SI H10-H18 derived from front-nine SI via +1 convention; not sourced from scorecard.
-- WARN: Red per-hole pars confirmed by club website (M/W PAR per hole listed on carradalegolf.com).

do $$
declare
    v_course_id integer;
    v_tee_id_1 integer;
begin

    -- Insert course
    insert into public.course (name, city, country, website, "approvalStatus", "submittedBy")
    values ('Carradale Golf Club', 'Carradale', 'Scotland', 'https://www.carradalegolf.com', 'pending', null)
    returning id into v_course_id;

    -- Insert Red tee (ladies)
    -- CR 62.8 / Slope 105 / Par 66 (33+33 symmetric)
    -- CR confirmed: GolfSherpa 62.8 + GolfShake SSS 63 (consistent rounding)
    -- Slope 105: GolfSherpa only (WARN: single-source, no contradiction)
    -- Distances: GolfPass H1-H9 = 1960 yards; back nine same physical holes = 1960 yards
    -- SI H1-H9: GolfPass Handicap (W) = 15,1,9,3,17,7,11,13,5 (all-odd)
    -- SI H10-H18: derived (+1 per hole) = 16,2,10,4,18,8,12,14,6 (all-even; covers 1-18 uniquely)
    -- Per-hole pars: club website confirms W PAR per hole; H3=par4 (219yds ladies), all others match M PAR
    insert into public."teeInfo" (
        "courseId", name, gender,
        "courseRating18", "slopeRating18",
        "courseRatingFront9", "slopeRatingFront9",
        "courseRatingBack9", "slopeRatingBack9",
        "outPar", "inPar", "totalPar",
        "outDistance", "inDistance", "totalDistance",
        "distanceMeasurement", "approvalStatus", "submittedBy"
    )
    values (
        v_course_id, 'Red', 'ladies',
        62.8, 105,
        31.4, 105,
        31.4, 105,
        33, 33, 66,
        1960, 1960, 3920,
        'yards', 'pending', null
    )
    returning id into v_tee_id_1;

    -- Holes for Red (ladies) — front nine
    -- Distances: GolfPass; Pars: club website (W PAR); SI: GolfPass Handicap (W)
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 1, 3, 143, 15);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 2, 4, 310, 1);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 3, 4, 219, 9);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 4, 4, 242, 3);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 5, 4, 254, 17);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 6, 4, 244, 7);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 7, 3, 167, 11);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 8, 3, 120, 13);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 9, 4, 261, 5);

    -- Holes for Red (ladies) — back nine (same physical holes, second rotation)
    -- Distances: same as front nine (symmetric twice-around)
    -- Pars: same as front nine (W par 66 = 33+33; no asymmetry on Red tee)
    -- SI: front-nine SI + 1 per hole (derived; standard Scottish 9-hole twice-around convention)
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 10, 3, 143, 16);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 11, 4, 310, 2);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 12, 4, 219, 10);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 13, 4, 242, 4);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 14, 4, 254, 18);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 15, 4, 244, 8);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 16, 3, 167, 12);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 17, 3, 120, 14);
    insert into public.hole ("teeId", "holeNumber", par, distance, hcp)
    values (v_tee_id_1, 18, 4, 261, 6);

    raise notice 'Successfully inserted course: %', v_course_id;
end $$;
